/*
 * DES Key Schedule and S-Box Implementation
 * university 2022 Scheme - Data Encryption Standard
 * 
 * This program demonstrates the core components of DES:
 * 1. Key Schedule Generation (56-bit key -> 16 subkeys)
 * 2. S-Box substitution concept
 */

#include <stdio.h>
#include <stdint.h>
#include <string.h>

/* Standard DES S-Box (S1 only - for demonstration) */
/* S-box converts 6 bits to 4 bits */
const int S1[4][16] = {
    {14, 4, 13, 1, 2, 15, 11, 8, 3, 10, 6, 12, 5, 9, 0, 7},
    {0, 15, 7, 4, 14, 2, 13, 1, 10, 6, 12, 11, 9, 5, 3, 8},
    {4, 1, 14, 8, 13, 6, 2, 11, 15, 12, 9, 7, 3, 10, 5, 0},
    {15, 12, 8, 2, 4, 9, 1, 7, 5, 11, 3, 14, 10, 0, 6, 13}
};

/* Left shift rotations for key schedule */
const int shift_schedule[16] = {
    1, 1, 2, 2, 2, 2, 2, 2, 1, 2, 2, 2, 2, 2, 2, 1
};

/* Function to rotate left by n bits in a 28-bit value */
uint32_t rotate_left(uint32_t value, int shift, int size) {
    shift = shift % size;
    return ((value << shift) | (value >> (size - shift))) & ((1 << size) - 1);
}

/* DES Key Schedule - Generate 16 subkeys from 64-bit key */
void generate_subkeys(uint64_t key, uint48_t subkeys[16]) {
    /* Note: In practice, proper PC-1 and PC-2 permutations needed */
    /* This is a simplified demonstration */

    uint32_t C = (uint32_t)(key & 0xFFFFFFF);      /* Left 28 bits */
    uint32_t D = (uint32_t)((key >> 28) & 0xFFFFFFF); /* Right 28 bits */

    printf("Initial C0: 0x%07X\n", C);
    printf("Initial D0: 0x%07X\n", D);

    for (int i = 0; i < 16; i++) {
        /* Perform left rotation */
        C = rotate_left(C, shift_schedule[i], 28);
        D = rotate_left(D, shift_schedule[i], 28);

        /* Combine C and D (simplified - real implementation needs PC-2) */
        subkeys[i] = ((uint64_t)C << 28) | D;

        printf("Round %2d: C=0x%07X, D=0x%07X, Subkey=0x%012lX\n", 
               i + 1, C, D, (unsigned long)subkeys[i]);
    }
}

/* S-Box Substitution - 6 bits input to 4 bits output */
int sbox_substitution(int input_6bits) {
    /* Extract row (first and last bits) */
    int row = ((input_6bits & 0x20) >> 4) | (input_6bits & 0x01);

    /* Extract column (middle 4 bits) */
    int col = (input_6bits >> 1) & 0x0F;

    /* Look up in S1 box */
    int output_4bits = S1[row][col];

    return output_4bits;
}

/* Demonstrate the f-function (Feistel function) concept */
uint32_t feistel_function(uint32_t R, uint64_t subkey) {
    /* Step 1: Expansion - 32 bits to 48 bits (simplified) */
    uint48_t expanded = 0;
    /* In practice, use proper expansion permutation table */

    /* Step 2: XOR with subkey */
    uint48_t xored = expanded ^ subkey;

    /* Step 3: S-Box substitution - 48 bits to 32 bits */
    uint32_t result = 0;
    for (int i = 0; i < 8; i++) {
        int six_bits = (xored >> (42 - i * 6)) & 0x3F;
        int four_bits = sbox_substitution(six_bits);
        result = (result << 4) | four_bits;
    }

    /* Step 4: Permutation (simplified) */
    return result;
}

void print_binary_64(uint64_t value) {
    for (int i = 63; i >= 0; i--) {
        printf("%d", (value >> i) & 1);
        if (i % 8 == 0 && i != 0) printf(" ");
    }
    printf("\n");
}

int main() {
    printf("=====================================================\n");
    printf("DES Key Schedule and S-Box Demonstration\n");
    printf("=====================================================\n\n");

    /* Example 64-bit key (8 bytes) with parity bits */
    uint64_t test_key = 0x133457799BBCDFF1;

    printf("Original 64-bit Key: 0x%016lX\n", (unsigned long)test_key);
    printf("Binary representation:\n");
    print_binary_64(test_key);
    printf("\nNote: Only 56 bits used for encryption (8 bits are parity)\n\n");

    /* Generate subkeys */
    uint48_t subkeys[16];
    printf("--- Key Schedule (16 Rounds) ---\n");
    generate_subkeys(test_key, subkeys);

    printf("\n--- S-Box Substitution Demo ---\n");
    /* Test S-box with sample input */
    int test_input = 0x3F;  /* 6-bit input: 111111 */
    int sbox_output = sbox_substitution(test_input);
    printf("Input (6 bits):  %02X\n", test_input);
    printf("Row: %d, Col: %d\n", 
           ((test_input & 0x20) >> 4) | (test_input & 0x01),
           (test_input >> 1) & 0x0F);
    printf("Output (4 bits): %X\n", sbox_output);

    printf("\n--- DES Security Summary ---\n");
    printf("- Key size: 56 bits (effective)");
    printf("  -> Vulnerable to brute force\n");
    printf("- Block size: 64 bits -> Too small for modern standards\n");
    printf("- 16 rounds of substitution and permutation\n");
    printf("- Replaced by AES (128/192/256-bit keys)\n");

    return 0;
}
